import os, django
os.environ.setdefault('DJANGO_SETTINGS_MODULE', 'skillscontinua_core.settings')
django.setup()

from courses.models import Course, Lesson

def add_lessons(title, lessons_data):
    try:
        course = Course.objects.get(title=title)
        Lesson.objects.filter(course=course).delete()
        for order, lesson_title, duration, content in lessons_data:
            Lesson.objects.create(
                course=course, title=lesson_title, content_type='text',
                content_text=content, order=order,
                duration_minutes=duration, is_active=True
            )
        print(f'OK: {title} — {course.lessons.count()} lessons')
    except Course.DoesNotExist:
        print(f'NOT FOUND: {title}')

# ============================================================
# MOTORCYCLE AND TRICYCLE REPAIRS
# ============================================================
add_lessons('Motorcycle and Tricycle Repairs', [
    (1, 'Introduction to Motorcycle and Tricycle Systems', 20,
     'Motorcycles and tricycles are the most common commercial vehicles across West Africa. Understanding how they work is the first step to repairing them.\n\nWHY THIS TRADE IS VALUABLE:\nOkada (motorcycle taxis), kekes and achabas (tricycle taxis) number in the millions across West Africa.\nEvery one needs regular maintenance and occasional repairs.\nA skilled motorcycle mechanic is never short of work.\nStartup costs are low compared to car mechanics.\n\nTHE FOUR SYSTEMS OF A MOTORCYCLE:\nEngine system: Converts fuel into mechanical power.\nTransmission system: Transfers power from engine to rear wheel.\nElectrical system: Battery, starter, lights, ignition.\nChassis system: Frame, wheels, brakes, suspension, steering.\n\nCOMMON MOTORCYCLES IN WEST AFRICA:\nHonda CG125 and similar Chinese copies: Most common. Simple, robust, easy to maintain.\nYamaha AG100/AG200: Popular in Nigeria.\nSuzuki GN125: Common across the region.\nTricycles (keke): Usually 200-250cc engines, three wheels, passenger or cargo body.\n\nTOOLS NEEDED TO START:\nSpanner set (metric): 8mm to 19mm most used.\nScrewdrivers: Flat and Phillips, multiple sizes.\nPliers: Regular and long-nose.\nSocket set: 10mm to 19mm.\nTyre levers: For removing and fitting tyres.\nTyre pressure gauge.\nMultimeter: For electrical diagnosis.\nFeeler gauges: For valve clearance and plug gap.\nFunnel and oil drain container.\n\nPRACTICAL EXERCISE:\nExamine any available motorcycle.\nIdentify: Engine, fuel tank, battery, front and rear brakes, spark plug, air filter, oil filler cap.\nTrace the cable from the throttle to the carburettor.\nFind the chain and identify the sprockets.\nWrite down what you observed.'),

    (2, 'Engine Maintenance and Servicing', 30,
     'Regular engine maintenance is the most important service a motorcycle needs.\n\nTHE SERVICE INTERVAL:\nMost small motorcycles should be serviced every 2,000 to 3,000 km or every 3 months.\nA basic service includes: oil change, spark plug check, air filter clean, chain adjustment, brake check.\n\nOIL CHANGE:\nWhy: Engine oil degrades over time and loses its lubricating properties.\nWhen: Every service. Never skip oil changes.\nHow:\nWarm the engine for 2 minutes (warm oil drains more completely).\nRemove the drain plug. Allow all oil to drain into a container.\nReplace the drain plug. Do not overtighten.\nFill with the correct oil type and quantity (check owner manual).\nTypically 1-1.5 litres of 10W40 engine oil for 125cc engines.\nCheck dipstick — between MIN and MAX marks.\n\nSPARK PLUG:\nThe spark plug ignites the fuel-air mixture.\nA worn or fouled plug causes: hard starting, rough running, poor fuel economy.\nCheck: Remove plug. Gap should be 0.6-0.8mm. Clean with wire brush if fouled.\nReplace: If electrode is worn, burned or heavily fouled.\nFouled black plug: Rich mixture or oil burning.\nWhite or grey plug: Too lean or overheating.\n\nAIR FILTER:\nBlocked air filter causes rich mixture, poor performance, black exhaust smoke.\nPaper filter: Replace every service.\nFoam filter: Wash with petrol, dry completely, coat lightly with clean oil.\n\nCAM CHAIN AND VALVE CLEARANCE:\nOn four-stroke engines, check valve clearance every other service.\nIncorrect clearance causes: noisy engine (too loose) or burnt valves (too tight).\nRequires feeler gauges and knowledge of the specific engine.\n\nPRACTICAL EXERCISE:\nConduct a full basic service on a motorcycle.\nChange oil, check and clean spark plug, clean air filter, check all fluid levels.\nCheck tyre pressures, check brake adjustment.\nRecord the service in a book: Date, mileage, parts used, observations.'),

    (3, 'Electrical System Diagnosis', 25,
     'Electrical problems are common and frighten many mechanics. A systematic approach solves them every time.\n\nTHE MOTORCYCLE ELECTRICAL SYSTEM:\nBattery: Stores electrical energy. Typically 12V, 5-12Ah.\nAlternator (generator): Charges battery when engine runs.\nRegulator/rectifier: Controls charging voltage.\nIgnition coil: Produces high voltage for spark.\nCDI unit: Controls ignition timing (on most modern motorcycles).\nStarter motor: Electric starter.\nLights: Headlight, tail light, indicators.\n\nCOMMON ELECTRICAL FAULTS:\n\nBATTERY NOT CHARGING:\nTest: Multimeter across battery. Should read 12.4-12.8V at rest.\nShould read 13.5-14.5V with engine running (alternator charging).\nIf not charging: Check alternator output, regulator/rectifier, wiring connections.\n\nWON\'T START:\nCheck battery voltage first.\nCheck main fuse (often under seat or near battery).\nCheck kill switch is in RUN position.\nCheck neutral switch if engine only starts in neutral.\nCheck spark: Remove plug, ground it on engine, kick starter. Should spark blue.\n\nLIGHTS NOT WORKING:\nCheck fuse first. Then check bulb. Then check switch.\nTrace wiring from switch to light, testing for power at each connector.\n\nHORN NOT WORKING:\nCheck fuse. Check horn switch. Test horn directly with battery.\n\nUSING A MULTIMETER:\nVoltage test (DC): Red to positive, black to negative. Read voltage.\nContinuity test: Check if a circuit is complete. Beep means circuit is complete.\nResistance: Check coil windings, sensors.\n\nPRACTICAL EXERCISE:\nTest battery voltage at rest and with engine running.\nTest that the charging system is working.\nLocate and identify all fuses on any available motorcycle.\nTrace the wiring from the horn switch to the horn.'),

    (4, 'Brakes, Tyres and Suspension', 25,
     'These are safety-critical systems. A motorcycle with failed brakes kills people. Take these seriously.\n\nBRAKE SYSTEMS:\n\nDRUM BRAKES (most common on budget motorcycles):\nBrake shoes inside a drum. Cable or rod operated.\nCheck: Cable tension, shoe thickness, drum condition.\nAdjust: Cable adjuster at lever or brake plate to take up slack.\nReplace shoes when: Thickness below 2mm, or brake feels spongy despite adjustment.\n\nDISC BRAKES (better motorcycles and tricycles):\nCaliper squeezes pads onto disc.\nHydraulic: Uses brake fluid. Check fluid level, check for leaks.\nCheck: Pad thickness (minimum 2mm), disc thickness, no scoring.\nBleed hydraulic system if spongy: Remove air bubbles from brake line.\n\nTYRES:\nCheck pressure every week: Typically front 25-28 psi, rear 28-32 psi (check specification).\nUnder-inflated: Excessive wear, poor handling, high fuel consumption.\nOver-inflated: Hard ride, reduced grip, faster wear in centre.\nReplace when: Tread depth below 1mm, sidewall damage, cuts.\n\nTYRE CHANGING:\nDeflate tyre completely.\nLeverage tyre bead off rim with tyre levers (use three, working around).\nRemove inner tube. Check for puncture: inflate tube, listen for air.\nPatch or replace tube.\nFit tube into tyre. Fit tyre onto rim. Inflate gradually. Check no tube is pinched.\n\nSUSPENSION:\nFront forks: Oil inside absorbs impacts. If leaking, seals must be replaced.\nRear shock: Often a simple spring-damper unit. Replace if bottoming out or leaking.\n\nCHAIN MAINTENANCE:\nCheck tension: Should have 20-30mm of free play at midpoint.\nAdjust by loosening rear axle and moving wheel back (rear wheel must stay aligned).\nLubricate every 300-500 km with chain lubricant.\nReplace when chain is stretched (measure 24 links — should not exceed 305mm for standard chain).\n\nPRACTICAL EXERCISE:\nCheck and adjust front and rear brake cable tension.\nCheck tyre pressures and condition.\nAdjust chain tension.\nDemonstrate a puncture repair on an inner tube.'),

    (5, 'Running a Motorcycle Repair Workshop', 20,
     'Technical skill is only half the business. The other half is running the workshop profitably.\n\nSETTING UP YOUR WORKSHOP:\nLocation: On a busy road where motorcycles pass. Near a fuel station or market.\nEquipment: Workbench or clean floor, tool storage, parts storage.\nCleanliness: A clean workshop signals professionalism and attracts customers.\nSafety: No smoking near fuel. Fire extinguisher accessible. Dispose of used oil correctly.\n\nPRICING MOTORCYCLE REPAIRS:\nParts: At cost plus 20-30% markup.\nLabour: By the job or by the hour. Research local rates.\nExamples:\nBasic service: Le 25,000-40,000 labour plus parts.\nTyre change: Le 5,000-10,000 labour.\nEngine overhaul: Le 150,000-300,000 labour plus parts.\nElectrical diagnosis and repair: Le 15,000-50,000 depending on fault.\n\nPARTS SOURCING:\nBuild relationships with spare parts dealers.\nKeep a small stock of fast-moving parts: Spark plugs, chain links, inner tubes, brake cables.\nThis allows you to complete jobs without delay — which customers appreciate.\nNever fit substandard parts. Your reputation depends on the quality of your work.\n\nCUSTOMER RELATIONSHIPS:\nMost okada and keke drivers use the same mechanic consistently.\nWin their trust and you have a customer for life.\nBe honest about faults. Show them the worn part before replacing it.\nCall them when their vehicle is ready — never leave them waiting without updates.\nKeep a customer book: Name, phone number, motorcycle details, service history.\n\nGROWING THE BUSINESS:\nOffer mobile service: Go to breakdowns for a premium fee.\nTake contracts with small transport companies for fleet maintenance.\nTrain an apprentice and expand capacity.\nSpecialise in specific brands that you know deeply.\n\nPRACTICAL EXERCISE:\nWrite a price list for your 10 most common services.\nCreate a simple customer record card.\nCalculate: If you do 4 basic services per day for 25 days, what is your monthly labour income?\nWhat parts inventory would you need to start a workshop?'),
])

# ============================================================
# TAILORING AND FASHION DESIGN
# ============================================================
add_lessons('Tailoring and Fashion Design', [
    (1, 'Introduction to Tailoring and Equipment', 20,
     'Tailoring transforms fabric into clothing. It is one of the oldest and most sustainable trades, with consistent demand in every community.\n\nWHY TAILORING IS AN EXCELLENT TRADE:\nEvery person needs clothing. Clothing wears out and must be replaced.\nSpecial occasions (weddings, funerals, graduations, naming ceremonies) always need tailoring.\nUnique, well-fitted garments command premium prices.\nLow startup costs compared to many other trades.\nWork from home or a small shop.\n\nEQUIPMENT:\nSewing machine: The most important tool. Singer, Butterfly and similar machines are common in West Africa.\nManual machines are more reliable than electric in areas with unreliable power.\nMaintain regularly: Oil moving parts, keep needle sharp, clean bobbin area.\n\nHand sewing tools:\nNeedles in various sizes.\nThimble: Protects finger when pushing needle.\nSeam ripper: Removes stitches without damaging fabric.\nPins and pin cushion.\n\nMeasuring and cutting tools:\nTape measure (flexible): For taking body measurements.\nRuler and metre stick: For marking straight lines.\nTailor\'s chalk: Marks fabric without permanent marks.\nPattern paper or newspaper: For drafting patterns.\nScissors: Sharp fabric scissors (never use for paper — dulls the blade).\nRotary cutter and mat: For accurate straight cuts.\n\nIRON: Essential for professional finishing. Every seam should be pressed as it is sewn.\n\nFABRICS COMMON IN WEST AFRICA:\nAnkara (African print wax fabric): Bold patterns. Used for traditional and modern styles.\nASO-OKE: Handwoven fabric used for special occasions.\nGeorge fabric: Used for traditional attire especially in Niger Delta.\nPlain cotton: Shirts, blouses, school uniforms.\nPolyester: Easy care, wide range of colours.\n\nPRACTICAL EXERCISE:\nIf you have access to a sewing machine, thread it correctly.\nSew a straight line on scrap fabric. Check stitch tension.\nSew a seam. Press it open.\nIdentify five different types of fabric and describe their properties.'),

    (2, 'Taking Measurements and Drafting Patterns', 30,
     'Accurate measurements and well-drafted patterns are the foundation of well-fitted clothing.\n\nTAKING BODY MEASUREMENTS:\nAlways use a flexible tape measure.\nAlways take measurements over a fitted garment, not bulky clothing.\nRecord all measurements in a customer measurement book.\n\nKEY MEASUREMENTS:\nChest/Bust: Around the fullest part of the chest.\nWaist: Around the natural waist (narrowest point of the torso).\nHips: Around the fullest part of the hips.\nShoulder width: From shoulder point to shoulder point across the back.\nBack length: From base of neck to natural waist.\nSleeve length: From shoulder point to wrist with arm slightly bent.\nFront length (for tops): From shoulder to desired hem.\nInseam: From crotch to ankle.\nOutseam: From natural waist to ankle.\nThigh: Around the fullest part of the thigh.\n\nEASE:\nEase is extra room added to measurements for comfort and movement.\nTight-fitting garment: 2-4cm ease.\nRegular fit: 4-8cm ease.\nLoose fit: 8cm or more.\nNever draft a pattern to exact body measurements — the garment will be unwearable.\n\nDRAFTING A BASIC BODICE PATTERN:\nA pattern is a template cut from paper used to cut fabric.\nBasic patterns (blocks) are drafted from measurements and used as foundations for many styles.\nStart with the back bodice:\nDraw a vertical line for centre back.\nAdd shoulder width, back length, armhole depth from measurements plus ease.\nCurve armhole, shape side seam, shape neck.\nDraft front bodice similarly.\nSide seams of front and back should match.\n\nCOMMERCIAL PATTERNS:\nPatterns from brands like Simplicity or Butterick are available.\nSizes often differ from West African sizing — adjust from measurements.\nTrace pattern pieces from the master sheet to preserve the original.\n\nPRACTICAL EXERCISE:\nMeasure a classmate or family member and record all 10 measurements.\nDraft a simple rectangular skirt pattern from their waist and hip measurements.\nCut the pattern from newspaper and check it against the person.'),

    (3, 'Cutting and Sewing Techniques', 30,
     'Cutting and sewing accurately is the technical core of tailoring.\n\nPREPARING FABRIC:\nWash and press fabric before cutting (pre-shrinking).\nFold fabric with right sides together for cutting (most patterns are cut on fold).\nEnsure grain line runs parallel to selvedge (the factory edge).\nOff-grain cutting causes garments to hang crookedly.\n\nCUTTING:\nPin pattern pieces to fabric.\nCut around pattern pieces with smooth, long cuts.\nDo not lift fabric off the table while cutting.\nCut notches outward to help match seams during assembly.\nTransfer all pattern markings to fabric with chalk or tracing wheel.\n\nSEAM ALLOWANCE:\nThe gap between the cut edge and the stitch line.\nStandard seam allowance: 1.5cm (5/8 inch).\nAlways sew at the marked seam allowance, not by eye.\n\nBASIC MACHINE SEWING:\nStraight stitch: For seams.\nZigzag stitch: For finishing raw edges to prevent fraying.\nBasting stitch: Long temporary stitch to hold pieces together for fitting.\n\nJOINING SEAMS:\nPin pieces right sides together, matching notches and markings.\nSew at seam allowance. Backstitch at beginning and end to secure.\nPress seam open or to one side as the pattern indicates.\n\nCOMMON SEWING PROBLEMS AND SOLUTIONS:\nThread breaking: Re-thread correctly. Check needle is not blunt.\nSkipped stitches: Change needle (probably bent or blunt).\nPuckered seam: Reduce tension or stitch length.\nUneven seam: Sew more slowly. Use a guide.\n\nFINISHING TECHNIQUES:\nSingle-fold hem: Fold once, press, stitch.\nDouble-fold hem: Fold twice, press, stitch. Cleaner finish.\nFacing: A fabric piece that finishes necklines and armholes from the inside.\nLining: A second layer of fabric inside the garment for a luxury finish.\n\nPRACTICAL EXERCISE:\nCut and sew a simple pillowcase or tote bag as practice.\nPractice: A straight seam, a curved seam, a hem.\nCheck your stitch tension on scrap fabric before starting.\nPress every seam after sewing.'),

    (4, 'Traditional and Modern African Styles', 25,
     'West African fashion blends rich traditional heritage with modern design. Mastering both opens the widest client base.\n\nTRADITIONAL STYLES:\n\nANKARA STYLES:\nAnkara fabric (wax print) is the most versatile African fabric.\nStyles include: Wrap skirts, fitted dresses, palazzo trousers, jumpsuits, blouses.\nPattern matching: Bold prints require careful alignment at seams.\nCutting: Plan cutting to maximise pattern symmetry at neckline, centre front, seams.\n\nKABA AND SLIT (Ghana):\nTwo-piece outfit: A fitted bodice (kaba) with a wrapped skirt (slit).\nUsually made in one fabric with matching or contrasting accessories.\n\nBUBU (Boubou):\nLong flowing robe common in Sierra Leone, Senegal, Guinea.\nSimple construction but quality of fabric and embroidery determines the price.\n\nASEBI (Matching):\nFamilies and groups wearing identical fabric at special occasions.\nOpportunity for large orders from one event.\n\nMODERN AFRICAN FASHION:\nAfrican fabric in modern Western silhouettes.\nAnkara blazers, Ankara sneakers, Ankara accessories.\nFusion: Combining African print panels with plain fabric.\nExporting: African fashion designers now sell globally online.\n\nSPECIAL OCCASION TAILORING:\nWedding attire: The highest-value tailoring work. Requires exceptional skill and patience.\nSchool uniforms: Reliable repeat orders. Price competitively for volume.\nWorkwear: Corporate uniform contracts can provide steady income.\nChurch outfits: Sunday best is important in West African culture.\n\nMEASUREMENT FOR TRADITIONAL STYLES:\nBubu: Mainly shoulder width and length.\nKaba and slit: Full set of measurements for fitted bodice.\nAnkara dress: Full set of measurements for fitted styles.\n\nPRACTICAL EXERCISE:\nMake one traditional African garment style relevant to your community.\nOptions: Simple bubu, wrap skirt, or fitted Ankara top.\nFocus on: Accurate cutting, pattern matching, clean finishing.\nPresent your finished garment and explain your construction process.'),

    (5, 'Running a Tailoring Business', 20,
     'A skilled tailor with business knowledge builds a profitable, lasting enterprise.\n\nSETTING YOUR PRICES:\nCalculate cost of fabric per garment.\nAdd thread, interfacing and other materials.\nCalculate your labour time and apply your hourly rate.\nAdd overhead (rent, electricity, equipment maintenance).\nAdd profit margin.\n\nExample: Simple Ankara dress:\nFabric (3m at Le 25,000/m): Le 75,000\nMaterials (thread, zip, interfacing): Le 8,000\nLabour (5 hours at Le 15,000): Le 75,000\nOverhead: Le 10,000\nTotal cost: Le 168,000\nSelling price (30% margin): Le 218,400 (round to Le 220,000)\n\nCUSTOMER MANAGEMENT:\nAlways take measurements before collecting deposit.\nRequire 50% deposit before buying fabric.\nSet a realistic completion date and meet it every time.\nDo a fitting before completing — alterations are expected.\nDeliver clean, pressed, professionally finished garments.\n\nBUILDING A PORTFOLIO:\nPhotograph every garment you make.\nBuild a WhatsApp or Instagram portfolio.\nCustomers who cannot describe what they want can point at photos.\nPortfolio work builds your reputation beyond word of mouth.\n\nASEBI CONTRACTS:\nApproach event organisers and group coordinators.\nOffer to make matching outfits for occasions.\nThis is high volume, predictable work.\nRequires excellent time management to deliver on time.\n\nGROWING THE BUSINESS:\nTrain an apprentice and take more orders.\nSpecialise in one type: Bridal, corporate, children\'s.\nOffer alterations and repairs as steady income alongside new work.\nBuild relationships with fabric sellers for referrals and wholesale prices.\n\nPRACTICAL EXERCISE:\nCalculate the price for your next three garments using the full costing method.\nCreate a simple customer order book: Name, measurements, order details, deposit paid, due date.\nResearch: What are the most popular styles in your area right now?\nTake photographs of your three best pieces and create your portfolio.'),
])

